import React, { useEffect, useState, useRef } from 'react';
import Navigation from './Navigation';
import Footer from './Footer';
import { useLocation } from 'react-router-dom';
function Contact() {
   const [menuOpen, setMenuOpen] = useState(false);
    const location = useLocation();

    useEffect(() => {
      setMenuOpen(false);
    }, [location.pathname]);

    const scrollToSection = (id) => {
      const element = document.getElementById(id);
      if (element) {
        element.scrollIntoView({ behavior: 'smooth' });
        setMenuOpen(false);
      }
    };

  const sectionRef = useRef(null);
  const [isVisible, setIsVisible] = useState(false);
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    date: "",
    message: "",
  });

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
        }
      },
      { threshold: 0.1 }
    );

    if (sectionRef.current) {
      observer.observe(sectionRef.current);
    }

    return () => observer.disconnect();
  }, []);

  const handleSubmit = (e) => {
    e.preventDefault();
    alert("Thank you for your inquiry! I will get back to you soon.");
  };

  return (
    <><Navigation
        menuOpen={menuOpen}
        setMenuOpen={setMenuOpen}
        />
    <section id="contact" className="contact" ref={sectionRef}>
      <div className="contact-container">

        {/* LEFT SIDE */}
        <div className={`contact-info ${isVisible ? "fade-in-left" : ""}`}>
          <p className="section-label">Get in Touch</p>
          <h2 className="section-title">Let's Create Something Beautiful</h2>
          <div className="section-divider"></div>

          <p className="contact-text">
            Ready to tell your story? I'd love to hear about your vision and
            discuss how we can create something extraordinary together.
          </p>

          <div className="contact-details">
            <div className="contact-item">
              <span className="contact-label">Email</span>
              <a href="mailto:hello@jaydabgar.com" className="contact-value">
                hello@jaydabgar.com
              </a>
            </div>

            <div className="contact-item">
              <span className="contact-label">Phone</span>
              <a href="tel:+1234567890" className="contact-value">
                +1 (234) 567-890
              </a>
            </div>

            <div className="contact-item">
              <span className="contact-label">Studio</span>
              <span className="contact-value">New York, NY</span>
            </div>
          </div>

          <div className="social-links">
            <a href="#" className="social-link">Instagram</a>
            <a href="#" className="social-link">Facebook</a>
            <a href="#" className="social-link">Pinterest</a>
          </div>
        </div>

        {/* RIGHT SIDE FORM */}
        <form
          className={`contact-form ${isVisible ? "fade-in-right" : ""}`}
          onSubmit={handleSubmit}
        >
          <div className="form-group">
            <label>Your Name</label>
            <input
              type="text"
              value={formData.name}
              onChange={(e) =>
                setFormData({ ...formData, name: e.target.value })
              }
              required
            />
          </div>

          <div className="form-group">
            <label>Email Address</label>
            <input
              type="email"
              value={formData.email}
              onChange={(e) =>
                setFormData({ ...formData, email: e.target.value })
              }
              required
            />
          </div>

          <div className="form-group">
            <label>Event Date</label>
            <input
              type="date"
              value={formData.date}
              onChange={(e) =>
                setFormData({ ...formData, date: e.target.value })
              }
            />
          </div>

          <div className="form-group">
            <label>Tell Me Your Story</label>
            <textarea
              rows="5"
              value={formData.message}
              onChange={(e) =>
                setFormData({ ...formData, message: e.target.value })
              }
              required
            ></textarea>
          </div>

          <button type="submit" className="btn-submit">
            Send Message
          </button>
        </form>
      </div>
    </section>
    <Footer />
    </>
  );
}

export default Contact;
